import time
import random
import math

def solve(instance: dict, tools: dict, time_limit_s: float) -> dict:
    """
    A Simulated Tempering / Variable Neighborhood Descent approach that differs from 
    the portfolio by avoiding purely greedy construction and simple local swaps.

    Instead of relying on deterministic greedy orderings, it uses a Tabu-inspired
    perturbation mechanism: it iteratively 'shatters' the current packing by 
    removing a subset of pieces (a 'cut') and re-packing them using randomized 
    try-place-piece seeds.
    """
    start_time = time.time()

    # 1. Initial State: Start with a high-performing greedy baseline
    best_sol = {"total_value": 0, "placements": []}
    try:
        initial = tools['bottom_left_pack_demand_aware']()
        best_sol = {"total_value": tools['total_value_of'](initial), "placements": initial}
    except Exception:
        pass

    # 2. Iterative Shattering and Re-insertion
    # Portfolio members rely on 'apply_local_swap' which is restrictive.
    # We implement a 'Shatter and Re-fill' loop.
    m = tools['n_piece_types']()

    while time.time() - start_time < time_limit_s * 0.8:
        current_placements = list(best_sol["placements"])
        if not current_placements:
            break

        # Perturbation: Remove a random subset of pieces (shatter)
        num_to_remove = random.randint(1, max(1, len(current_placements) // 2))
        random.shuffle(current_placements)
        remaining = current_placements[num_to_remove:]

        # Re-fill: Try to insert pieces back into the layout using randomized insertion
        # This differs from greedy construction by attempting to fill holes left by the cut
        shuffled_types = list(range(1, m + 1))
        random.shuffle(shuffled_types)

        working_placements = list(remaining)
        for t in shuffled_types:
            if tools['used_count'](working_placements, t) < tools['piece_demand_max'](t):
                # Try to add this piece type; try_place_piece is expensive but effective
                # for filling gaps left by removals
                res = tools['try_place_piece'](working_placements, t, orient=0)
                if res is not None:
                    working_placements = res

        # Evaluation
        new_val = tools['total_value_of'](working_placements)
        if new_val > best_sol["total_value"]:
            best_sol = {"total_value": new_val, "placements": working_placements}

        # Check time
        if time.time() - start_time > time_limit_s * 0.9:
            break

    # 3. Final polishing with local swap if time remains
    try:
        if time.time() - start_time < time_limit_s * 0.95:
            improved = tools['apply_local_swap'](
                best_sol["placements"], 
                t_limit=min(0.5, time_limit_s - (time.time() - start_time))
            )
            val = tools['total_value_of'](improved)
            if val > best_sol["total_value"]:
                best_sol = {"total_value": val, "placements": improved}
    except Exception:
        pass

    # Ensure validity
    is_valid, _ = tools['is_feasible'](best_sol)
    if not is_valid:
        # Fallback to pure greedy if shattering produced invalid state
        fallback = tools['guillotine_pack_BFD']()
        return {"total_value": tools['total_value_of'](fallback), "placements": fallback}

    return best_sol

import time
import random

def solve(instance: dict, tools: dict, time_limit_s: float) -> dict:
    """
    A dispatch-style heuristic for Constrained Guillotine Cutting.

    Dispatch Hypothesis:
    - Instances with a high 'diversity-to-stock' ratio (many small pieces relative 
      to stock area) benefit from the destructive-reconstructive approach (A), 
      which helps escape local optima in highly constrained packing.
    - Instances with a low 'diversity-to-stock' ratio (fewer, larger pieces) 
      benefit from the simulated annealing-like cooling schedule (B), which 
      systematically explores packing orders for larger, more impactful pieces.
    """
    start_time = time.time()
    stock_l, stock_w = tools['stock_dims']()
    stock_area = stock_l * stock_w
    n_types = tools['n_piece_types']()

    total_potential_area = 0
    for i in range(1, n_types + 1):
        l, w = tools['piece_dims'](i)
        total_potential_area += (l * w) * tools['piece_demand_max'](i)

    # Feature: Area Density Ratio
    # If total potential area is much larger than stock, the problem is 'tightly packed'.
    # If smaller or comparable, it's 'sparse'.
    density_ratio = total_potential_area / stock_area

    # Dispatch: 
    # High density_ratio -> A (Destructive-Reconstructive)
    # Low density_ratio -> B (Annealing-based construction)
    if density_ratio > 1.5:
        return _run_heuristic_a(tools, time_limit_s, start_time)
    else:
        return _run_heuristic_b(tools, time_limit_s, start_time)

def _run_heuristic_a(tools, time_limit_s, start_time):
    m = tools['n_piece_types']()
    indices = list(range(1, m + 1))

    def get_stochastic_order():
        densities = []
        for i in indices:
            l, w = tools['piece_dims'](i)
            v = tools['piece_value'](i)
            densities.append((v / (l * w + 1e-9), i))
        densities.sort(key=lambda x: x[0], reverse=True)
        order = [d[1] for d in densities]
        for i in range(len(order)):
            if random.random() < 0.2:
                j = random.randint(0, len(order) - 1)
                order[i], order[j] = order[j], order[i]
        return order

    best_sol = {"total_value": 0, "placements": []}
    while time.time() - start_time < time_limit_s * 0.9:
        if best_sol["placements"]:
            keep_count = int(len(best_sol["placements"]) * 0.5)
            work_placements = random.sample(best_sol["placements"], keep_count)
        else:
            work_placements = []

        for p_idx in get_stochastic_order():
            while tools['used_count'](work_placements, p_idx) < tools['piece_demand_max'](p_idx):
                attempt = tools['try_place_piece'](work_placements, p_idx)
                if attempt is not None:
                    work_placements = attempt
                else:
                    break
        val = tools['total_value_of'](work_placements)
        if val > best_sol["total_value"]:
            best_sol = {"total_value": val, "placements": work_placements}

    return best_sol

def _run_heuristic_b(tools, time_limit_s, start_time):
    m = tools['n_piece_types']()
    indices = list(range(1, m + 1))

    def get_stochastic_order(mode, temp):
        items = []
        for i in indices:
            l, w = tools['piece_dims'](i)
            v = tools['piece_value'](i)
            score = (v / (l * w + 1e-9)) if mode == 'density' else (l * w)
            items.append((score, i))
        items.sort(key=lambda x: x[0], reverse=True)
        order = [x[1] for x in items]
        jitter_prob = 0.4 * temp
        for i in range(len(order)):
            if random.random() < jitter_prob:
                j = random.randint(0, len(order) - 1)
                order[i], order[j] = order[j], order[i]
        return order

    best_sol = {"total_value": 0, "placements": []}
    iteration = 0
    while time.time() - start_time < time_limit_s * 0.85:
        temp = max(0.1, 1.0 - ((time.time() - start_time) / (time_limit_s * 0.85)))
        mode = 'density' if iteration % 2 == 0 else 'area'
        work_placements = []
        for p_idx in get_stochastic_order(mode, temp):
            while tools['used_count'](work_placements, p_idx) < tools['piece_demand_max'](p_idx):
                attempt = tools['try_place_piece'](work_placements, p_idx)
                if attempt is not None:
                    work_placements = attempt
                else:
                    break
        val = tools['total_value_of'](work_placements)
        if val > best_sol["total_value"]:
            best_sol = {"total_value": val, "placements": work_placements}
        iteration += 1

    if best_sol["placements"]:
        refined = tools['apply_local_swap'](best_sol["placements"], t_limit=max(0.1, time_limit_s * 0.1))
        best_sol = {"total_value": tools['total_value_of'](refined), "placements": refined}
    return best_sol

import time
import random

def solve(instance: dict, tools: dict, time_limit_s: float) -> dict:
    """
    A robust hybrid heuristic for the Constrained Guillotine Cutting problem.
    Combines diverse constructive baselines with a focused local search strategy
    that balances exploration (random perturbations) and exploitation (value-density
    greedy replacement).
    """
    start_time = time.time()
    m = tools['n_piece_types']()

    # Precompute metadata for informed greedy choices
    piece_meta = []
    for i in range(1, m + 1):
        l, w = tools['piece_dims'](i)
        val = tools['piece_value'](i)
        piece_meta.append({
            'id': i, 
            'val': val, 
            'area': l * w, 
            'density': val / (l * w + 1e-9)
        })

    best_sol = {"total_value": 0, "placements": []}

    def update_best(placements):
        nonlocal best_sol
        val = tools['total_value_of'](placements)
        if val > best_sol["total_value"]:
            best_sol = {"total_value": val, "placements": list(placements)}

    # 1. Construction Phase: Generate diverse starting points
    # Use different sorting strategies to explore the solution space
    strategies = [
        sorted(range(1, m + 1), key=lambda i: piece_meta[i-1]['density'], reverse=True),
        sorted(range(1, m + 1), key=lambda i: piece_meta[i-1]['area'], reverse=True),
        sorted(range(1, m + 1), key=lambda i: piece_meta[i-1]['val'], reverse=True),
    ]

    for order in strategies:
        if time.time() - start_time > time_limit_s * 0.2:
            break
        try:
            p = tools['bottom_left_pack_demand_aware'](piece_order=order)
            update_best(p)
        except:
            continue

    try:
        bfd = tools['guillotine_pack_BFD']()
        update_best(bfd)
    except:
        pass

    # 2. Refinement Phase: Local Search
    # Use apply_local_swap as a powerful engine for local improvement
    time_remaining = time_limit_s - (time.time() - start_time)
    if time_remaining > 0.1:
        try:
            improved = tools['apply_local_swap'](
                best_sol["placements"], 
                t_limit=time_remaining * 0.5
            )
            update_best(improved)
        except:
            pass

    # 3. Iterative Perturbation Phase
    # If time remains, perform a "shake" and re-fill to escape local optima
    current_placements = list(best_sol["placements"])
    candidates = sorted(piece_meta, key=lambda x: x['density'], reverse=True)

    while time.time() - start_time < time_limit_s * 0.95:
        if not current_placements:
            break

        # Remove a random subset to create space
        num_to_remove = max(1, len(current_placements) // 4)
        for _ in range(num_to_remove):
            if current_placements:
                current_placements.pop(random.randrange(len(current_placements)))

        # Try to fill with high-density pieces
        for cand in candidates:
            if tools['used_count'](current_placements, cand['id']) < tools['piece_demand_max'](cand['id']):
                attempt = tools['try_place_piece'](current_placements, cand['id'])
                if attempt:
                    current_placements = attempt
                    update_best(current_placements)

        # If we failed to improve, reset to best known
        if tools['total_value_of'](current_placements) < best_sol["total_value"]:
            current_placements = list(best_sol["placements"])

    # Final sanity check
    is_valid, _ = tools['is_feasible'](best_sol)
    if not is_valid:
        # Fallback to the most robust construction
        fallback = tools['guillotine_pack_BFD']()
        return {"total_value": tools['total_value_of'](fallback), "placements": fallback}

    return best_sol
